import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import { RadioGroup as RadioGroupPrimitive, useRadioGroup } from '@ark-ui/react/radio-group';
import { clsx } from 'clsx';
import { Children, cloneElement, forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './RadioGroup.module.css';

type RadioGroupItemControlSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type RadioGroupItemControlProps = ComponentProps<typeof RadioGroupPrimitive.ItemControl> & {
  size?: RadioGroupItemControlSize;
};
type RadioGroupOptionProps = Omit<
  ComponentProps<typeof RadioGroupPrimitive.Item>,
  'asChild' | 'children'
> & {
  children: ReactNode;
  size?: RadioGroupItemControlSize;
};

const RadioGroupRoot = forwardRef<
  ComponentRef<typeof RadioGroupPrimitive.Root>,
  ComponentProps<typeof RadioGroupPrimitive.Root>
>(function RadioGroupRoot({ className, ...props }, ref) {
  return (
    <RadioGroupPrimitive.Root
      ref={ref}
      data-slot="radio-group-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const RadioGroupRootProvider = forwardRef<
  ComponentRef<typeof RadioGroupPrimitive.RootProvider>,
  ComponentProps<typeof RadioGroupPrimitive.RootProvider>
>(function RadioGroupRootProvider({ className, ...props }, ref) {
  return (
    <RadioGroupPrimitive.RootProvider
      ref={ref}
      data-slot="radio-group-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const RadioGroupLabel = forwardRef<
  ComponentRef<typeof RadioGroupPrimitive.Label>,
  ComponentProps<typeof RadioGroupPrimitive.Label>
>(function RadioGroupLabel({ className, ...props }, ref) {
  return (
    <RadioGroupPrimitive.Label
      ref={ref}
      data-slot="radio-group-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const RadioGroupItem = forwardRef<
  ComponentRef<typeof RadioGroupPrimitive.Item>,
  ComponentProps<typeof RadioGroupPrimitive.Item>
>(function RadioGroupItem({ asChild, children, className, ...props }, ref) {
  return (
    <RadioGroupPrimitive.Item
      ref={ref}
      asChild={asChild}
      data-slot="radio-group-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    >
      {withItemHiddenInput(children, asChild)}
    </RadioGroupPrimitive.Item>
  );
});

const RadioGroupOption = forwardRef<
  ComponentRef<typeof RadioGroupPrimitive.Item>,
  RadioGroupOptionProps
>(function RadioGroupOption({ children, size, ...props }, ref) {
  return (
    <RadioGroupItem ref={ref} {...props}>
      <RadioGroupItemControl size={size} />
      <RadioGroupItemText>{children}</RadioGroupItemText>
    </RadioGroupItem>
  );
});

const RadioGroupItemControl = forwardRef<
  ComponentRef<typeof RadioGroupPrimitive.ItemControl>,
  RadioGroupItemControlProps
>(function RadioGroupItemControl({ className, size = 'md', ...props }, ref) {
  return (
    <RadioGroupPrimitive.ItemControl
      ref={ref}
      data-slot="radio-group-item-control"
      data-size={size}
      className={clsx(styles.itemControl, normalizeClassName(className))}
      {...props}
    />
  );
});

const RadioGroupItemText = forwardRef<
  ComponentRef<typeof RadioGroupPrimitive.ItemText>,
  ComponentProps<typeof RadioGroupPrimitive.ItemText>
>(function RadioGroupItemText({ className, ...props }, ref) {
  return (
    <RadioGroupPrimitive.ItemText
      ref={ref}
      data-slot="radio-group-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

function withItemHiddenInput(children: ReactNode, asChild?: boolean) {
  const hiddenInput = (
    <RadioGroupPrimitive.ItemHiddenInput data-slot="radio-group-item-hidden-input" />
  );

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInput}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInput);
}

const RadioGroupIndicator = forwardRef<
  ComponentRef<typeof RadioGroupPrimitive.Indicator>,
  ComponentProps<typeof RadioGroupPrimitive.Indicator>
>(function RadioGroupIndicator({ className, ...props }, ref) {
  return (
    <RadioGroupPrimitive.Indicator
      ref={ref}
      data-slot="radio-group-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const RadioGroup = Object.assign(RadioGroupRoot, {
  Root: RadioGroupRoot,
  RootProvider: RadioGroupRootProvider,
  Label: RadioGroupLabel,
  Item: RadioGroupItem,
  Option: RadioGroupOption,
  ItemControl: RadioGroupItemControl,
  ItemText: RadioGroupItemText,
  Indicator: RadioGroupIndicator,
});

export { RadioGroup, useRadioGroup };
export type { RadioGroupItemControlProps, RadioGroupItemControlSize, RadioGroupOptionProps };

@layer ui.components {
  .root {
    position: relative;
    display: flex;
    flex-direction: column;
    gap: var(--radio-group-gap, var(--spacing-2));
    color: var(--radio-group-color, var(--color-foreground));

    &[data-disabled] {
      cursor: default;
    }
  }

  .label {
    color: var(--radio-group-label-color, var(--radio-group-color, var(--color-foreground)));
    font-size: var(--radio-group-label-font-size, var(--text-sm));
    font-weight: var(--radio-group-label-font-weight, var(--weight-semibold));
    line-height: var(--radio-group-label-line-height, var(--line-height-text-sm));
  }

  .item {
    display: inline-flex;
    align-items: center;
    width: fit-content;
    gap: var(--radio-gap, var(--spacing-2));
    vertical-align: middle;
    cursor: pointer;

    &[data-disabled] {
      cursor: default;
      opacity: var(--radio-disabled-opacity, var(--opacity-disabled));
    }
  }

  .itemControl {
    box-sizing: border-box;
    position: relative;
    display: inline-flex;
    flex: none;
    align-items: center;
    justify-content: center;
    -webkit-appearance: none;
    appearance: none;
    width: var(--_radio-size, 1.25rem);
    height: var(--_radio-size, 1.25rem);
    border: var(--radio-border-width, var(--border-width-sm)) solid
      var(--radio-border-color, var(--color-border));
    border-radius: var(--radius-full);
    background-color: var(--radio-bg, var(--color-background));
    color: var(--radio-indicator-color, var(--color-primary-foreground));
    outline: 0;
    line-height: 0;
    user-select: none;
    transition:
      background-color var(--radio-transition, var(--transition-default)),
      border-color var(--radio-transition, var(--transition-default)),
      border-width var(--radio-transition, var(--transition-default)),
      color var(--radio-transition, var(--transition-default)),
      opacity var(--radio-transition, var(--transition-default));

    &::before {
      display: block;
      width: var(--_radio-indicator-size, 0.5rem);
      height: var(--_radio-indicator-size, 0.5rem);
      border: var(--radio-indicator-border-width, 0) solid
        var(--radio-indicator-border-color, currentColor);
      border-radius: var(--radio-indicator-radius, var(--radius-full));
      background-color: currentColor;
      content: '';
      opacity: 0;
      transform: scale(0.6);
      transition:
        opacity var(--radio-transition, var(--transition-default)),
        transform var(--radio-transition, var(--transition-default));
    }

    &[data-state='checked'] {
      border-color: var(--radio-border-color-checked, var(--color-primary));
      background-color: var(--radio-bg-checked, var(--color-primary));

      &::before {
        opacity: 1;
        transform: scale(1);
      }
    }

    &[data-focus-visible] {
      outline: var(--radio-focus-ring-width, var(--border-width-sm)) solid
        var(--radio-focus-ring-color, var(--color-ring));
      outline-offset: var(--radio-focus-ring-offset, var(--border-width-sm));
    }

    @media (hover: hover) {
      &[data-state='unchecked']:not([data-readonly], [data-disabled]):hover {
        background-color: var(--radio-bg-hover, var(--color-accent));
      }
    }

    &[data-readonly],
    &[data-disabled] {
      cursor: default;
    }

    &[data-size='xs'] {
      --_radio-size: var(--radio-size-xs, 0.875rem);
      --_radio-indicator-size: var(--radio-indicator-size-xs, 0.25rem);
    }

    &[data-size='sm'] {
      --_radio-size: var(--radio-size-sm, 1rem);
      --_radio-indicator-size: var(--radio-indicator-size-sm, 0.375rem);
    }

    &[data-size='md'] {
      --_radio-size: var(--radio-size-md, 1.25rem);
      --_radio-indicator-size: var(--radio-indicator-size-md, 0.5rem);
    }

    &[data-size='lg'] {
      --_radio-size: var(--radio-size-lg, 1.5rem);
      --_radio-indicator-size: var(--radio-indicator-size-lg, 0.625rem);
    }

    &[data-size='xl'] {
      --_radio-size: var(--radio-size-xl, 1.75rem);
      --_radio-indicator-size: var(--radio-indicator-size-xl, 0.75rem);
    }
  }

  .itemText {
    color: var(--radio-label-color, var(--color-foreground));
    font-size: var(--radio-label-font-size, var(--text-sm));
    font-weight: var(--radio-label-font-weight, var(--weight-medium));
    line-height: var(--radio-label-line-height, var(--line-height-text-sm));
  }

  .indicator {
    position: absolute;
    top: var(--top);
    left: var(--left);
    width: var(--width);
    height: var(--height);
    border-radius: var(--radio-indicator-radius, var(--radius-full));
    background-color: var(--radio-bg-checked, var(--color-primary));
    opacity: var(--radio-group-indicator-opacity, 0.12);
    pointer-events: none;
    transition: var(--transition-property, translate)
      var(--radio-transition, var(--transition-default));
  }
}

export { RadioGroup, useRadioGroup } from './RadioGroup';
export type {
  RadioGroupItemControlProps,
  RadioGroupItemControlSize,
  RadioGroupOptionProps,
} from './RadioGroup';
